def extract_politician_counts(articles, politician_names):
    counts = {}
    for article in articles:
        for name in politician_names:
            # convert to lowercase and remove punctuation
            name_lower = name.lower()
            article_lower = article.lower()
            # remove punctuation from article
            article_clean = article_lower.replace("?", "").replace(",", "").replace(".", "").replace("!", "")
            if name_lower in article_clean:
                counts[name_lower] = counts.get(name_lower, 0) + 1
    return counts
